# Token verification function
def verify_token(token, algorithm='HS256', public_key=None):
    try:
        if algorithm == 'HS256':
            # For HS256, use the secret key from config
            secret = app.config['JWT_SECRET_KEY']
            payload = jwt.decode(token, secret, algorithms=[algorithm])
        elif algorithm == 'RS256':
            # For RS256, use the public key
            if public_key is None:
                raise ValueError("Public key required for RS256")
            payload = jwt.decode(token, public_key, algorithms=[algorithm], options={"verify_signature": True})
        else:
            raise ValueError("Unsupported algorithm")
        
        # Validate claims
        if 'exp' in payload:
            if payload['exp'] < datetime.datetime.utcnow().timestamp():
                raise jwt.ExpiredSignatureError("Token has expired")
        
        if 'iat' in payload:
            if payload['iat'] > datetime.datetime.utcnow().timestamp():
                raise jwt.InvalidIssuedAtError("Token issued in the future")
        
        return payload
    except jwt.InvalidTokenError as e:
        raise ValueError(f"Invalid token: {str(e)}")

# Decorator for token validation
def validate_token(algorithm='HS256'):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            auth_header = request.headers.get('Authorization')
            if not auth_header or not auth_header.startswith('Bearer '):
                return jsonify({'msg': 'Missing or invalid authorization header'}), 401
            
            token = auth_header.split(' ')[1]
            
            try:
                payload = verify_token(token, algorithm)
                request.payload = payload
            except ValueError as e:
                return jsonify({'msg': str(e)}), 401
            
            return f(*args, **kwargs)
        return decorated_function
    return decorator

